import * as React from 'react';

// components
import IcoMoon, { IconProps } from 'react-icomoon';

// variables
import { Colors, FontSize } from '../components/common/variables';

// datas
import Data from './selection.json'

export const Icon = (props: IconProps) => (
  <IcoMoon iconSet={Data} {...props}  />
)

// Icons liste
export enum Items {
  Menu = "Menu",
  Close = "Close",
  Next = "Next",
  Back = "Back",
}

// types
type SIconProps = {
  icon: Items;
  size?: string;
  color?: string;
}

const SIcon: React.FC<SIconProps> = ({...props}) => {
  return (
    <Icon
      icon={Items[props.icon as keyof typeof Items].toString()}
      size={props.size ? props.size : FontSize.px16}
      color={props.color ? props.color : Colors.text.primary}
    />
  )
}

export default SIcon