// components
import { styled } from '@mui/material';

// variables
import { MediaQuery } from '../common/variables';

// types
type direction = {
  direction: string;
};
type slideIndex = {
  slideIndex: number;
};

export const Container = styled('div')`
  height: 80vh;
  display: flex;
  position: relative;
  overflow: hidden;
  width: 100vw;
  ${MediaQuery.tabletLarge({
    height: '50vh',
  })}
  ${MediaQuery.mobileLarge({
    height: '40vh',
    overflow: 'visble',
  })}
`;

export const Arrow = styled('div')<direction>`
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  position: absolute;
  top: 0;
  bottom: 0;
  /* buttons */
  left: ${(props) => props.direction === 'left' && '13vw'};
  right: ${(props) => props.direction === 'right' && '13vw'};
  margin: auto;
  cursor: pointer;
  opacity: 0.5;
  z-index: 2;
  transition: all 0.5s ease;
  &:hover {
    color: white;
    background-color: black;
  }
  @media (max-width: 600px) {
    left: ${(props) => props.direction === 'left' && '10vw'};
    right: ${(props) => props.direction === 'right' && '10vw'};
  };
`;

export const Wrapper = styled('section')<slideIndex>`
  display: flex;
  transition: all 1.5s ease;
  transform: translateX(${(props) => props.slideIndex * -100}vw);
`;

